import React from "react";
import { motion } from "framer-motion"; // Importamos motion para animaciones si quieres

// --- PALETA DE COLORES (tomada de tu componente InicioSesion y Legado Boliviano) ---
const PALETTE = {
  BACKGROUND_PRIMARY: "#F6EEE3", // Beige claro del fondo de Legado Boliviano y modal
  PRIMARY_ACCENT_BLUE: "#2F4F8B", // Azul oscuro fuerte
  SECONDARY_ACCENT_GOLD: "#E1B85D", // Dorado
  TEXT_DARK: "#25384F", // Un gris azulado oscuro para el texto principal
  TEXT_MUTED: "#78909C", // Gris más suave para detalles
  CONTOUR_COLOR: "#000000", // Color del contorno negro (para dar una sensación de marco)
};

const FooterBar = () => {
  const estilosFooterBar = {
    contenedor: {
      backgroundColor: PALETTE.BACKGROUND_PRIMARY, // Fondo beige claro
      padding: "35px 0", // Aumentar padding para más espacio
      textAlign: "center",
      borderTop: `2px solid ${PALETTE.CONTOUR_COLOR}`, // Contorno superior
      boxShadow: `0 -5px 15px rgba(0,0,0,0.1)`, // Sombra sutil hacia arriba
      fontFamily: "'Playfair Display', serif", // Fuente profesional
    },
    inner: {
      maxWidth: "1200px",
      margin: "0 auto",
      padding: "0 20px", // Padding horizontal para que no se pegue a los bordes en pantallas pequeñas
    },
    tutor: {
      fontSize: "18px", // Texto más grande
      color: PALETTE.TEXT_DARK, // Color oscuro del texto
      margin: "0 0 15px 0", // Espacio inferior
      fontWeight: 500, // Menos negrita
      letterSpacing: "0.5px", // Espaciado entre letras
    },
    enlaces: {
      marginTop: "10px",
      display: "flex",
      flexWrap: "wrap", // Permite que los enlaces se envuelvan en pantallas pequeñas
      justifyContent: "center",
      gap: "30px", // Más espacio entre enlaces
      listStyle: "none",
      padding: 0,
      margin: 0,
    },
    enlace: {
      textDecoration: "none",
      color: PALETTE.PRIMARY_ACCENT_BLUE, // Azul de acento
      fontSize: "17px", // Tamaño de fuente ligeramente más grande
      fontWeight: 600, // Un poco más de negrita
      transition: "color 0.3s ease, transform 0.2s ease", // Transición suave al hover
      letterSpacing: "0.5px",
    },
    // Estilos para el hover de los enlaces (usaremos motion.a de framer-motion)
    enlaceHover: {
      color: PALETTE.SECONDARY_ACCENT_GOLD, // Dorado al pasar el ratón
      transform: "translateY(-2px)", // Pequeño levantamiento
    }
  };

  return (
    <footer style={estilosFooterBar.contenedor}>
      <div style={estilosFooterBar.inner}>
        <p style={estilosFooterBar.tutor}>
          Tutorizado por: Alberto Navarro
        </p>
        <ul style={estilosFooterBar.enlaces}>
          <li>
            <motion.a
              style={estilosFooterBar.enlace}
              href="/contacto"
              whileHover={estilosFooterBar.enlaceHover}
              whileTap={{ scale: 0.95 }}
            >
              Contacto
            </motion.a>
          </li>
          <li>
            <motion.a
              style={estilosFooterBar.enlace}
              href="/acerca-de"
              whileHover={estilosFooterBar.enlaceHover}
              whileTap={{ scale: 0.95 }}
            >
              Acerca de
            </motion.a>
          </li>
          <li>
            <motion.a
              style={estilosFooterBar.enlace}
              href="/privacidad"
              whileHover={estilosFooterBar.enlaceHover}
              whileTap={{ scale: 0.95 }}
            >
              Privacidad
            </motion.a>
          </li>
        </ul>
      </div>
    </footer>
  );
};

export default FooterBar;
